// 增长进程空间？
// 1. 为新的进程空间分配内存
// 2. 为新的虚拟内存创建映射
// Allocate PTEs and physical memory to grow process from oldsz to
// newsz, which need not be page aligned.  Returns new size or 0 on error.

uint64
uvmalloc(pagetable_t pagetable, uint64 oldsz, uint64 newsz, int xperm)
{
  char *mem;
  uint64 a;

  if(newsz < oldsz)
    return oldsz;

  oldsz = PGROUNDUP(oldsz);
  for(a = oldsz; a < newsz; a += PGSIZE){
    //增长进程空间
    mem = kzalloc();
    if(mem == 0){
      uvmdealloc(pagetable, a, oldsz);
      return 0;
    }
    memset(mem, 0, PGSIZE);
    //为新的页创建物理映射
    if(mappages(pagetable, a, PGSIZE, (uint64)mem, PTE_R|PTE_U|xperm) != 0){
      kfree(mem);
      uvmdealloc(pagetable, a, oldsz);
      return 0;
    }
  }
  return newsz;
}

// 只能用于减少进程空间
// 1.解除页映射(解除过程中do_free)
// Deallocate user pages to bring the process size from oldsz to
// newsz.  oldsz and newsz need not be page-aligned, nor does newsz
// need to be less than oldsz.  oldsz can be larger than the actual
// process size.  Returns the new process size.

uint64
uvmdealloc(pagetable_t pagetable, uint64 oldsz, uint64 newsz)
{
  // 减少进程空间
  if(newsz >= oldsz)
    return oldsz;

  if(PGROUNDUP(newsz) < PGROUNDUP(oldsz)){
    int npages = (PGROUNDUP(oldsz) - PGROUNDUP(newsz)) / PGSIZE;
    uvmunmap(pagetable, PGROUNDUP(newsz), npages, 1);
  }

  return newsz;
}

// Recursively free page-table pages.
// All leaf mappings must already have been removed.

void
freewalk(pagetable_t pagetable)
{
  // there are 2^9 = 512 PTEs in a page table.
  for(int i = 0; i < 512; i++){
    pte_t pte = pagetable[i];
    // 有效位为1且RWX权限均为0
    // && 优先级最低
    if((pte & PTE_V) && (pte & (PTE_R|PTE_W|PTE_X)) == 0){
      // this PTE points to a lower-level page table.
      uint64 child = PTE2PA(pte);
      freewalk((pagetable_t)child);
      pagetable[i] = 0;
    } else if(pte & PTE_V){
#ifdef __DEBUG_FREEWALK
      Info("thread %d's trapframe in freewalk: %p\n", mythread()->tid, mythread()->trapframe);
      Info("panic pte %p, pa %p\n", pte,PTE2PA(pte));
#endif
      panic("freewalk: leaf");
    }
    //若均无效且无权限(到达已经被移除的叶映射节点)，则不会继续往下递归
  }
  kfree((void*)pagetable);
}

// Free user memory pages,
// then free page-table pages.

void
uvmfree(pagetable_t pagetable, uint64 sz)
{
  if(sz > 0)
    uvmunmap(pagetable, 0, PGROUNDUP(sz)/PGSIZE, 1);
#ifdef __DEBUG_UVMFREE
  vmprint(pagetable);
#endif
  freewalk(pagetable);
}

// Given a parent process's page table, copy
// its memory into a child's page table.
// Copies both the page table and the
// physical memory.
// returns 0 on success, -1 on failure.
// frees any allocated pages on failure.

int
uvmcopy(pagetable_t old, pagetable_t new, uint64 sz)
{
  pte_t *pte;
  uint64 pa, i;
  uint flags;
  char *mem;
#ifdef __DEBUG_UVMCOPY
  Log("uvmcopy: old %p, new %p, sz %p", old, new, sz);
#endif

  for(i = 0; i < sz; i += PGSIZE){
    if((pte = walk(old, i, 0)) == 0)
      panic("uvmcopy: pte should exist");
    if((*pte & PTE_V) == 0)
      panic("uvmcopy: page not present");
    pa = PTE2PA(*pte);
    flags = PTE_FLAGS(*pte);
    if((mem = kalloc()) == 0)
      goto err;
    // 复制父进程内存
    memmove(mem, (char*)pa, PGSIZE);
    // 建立子进程映射
    if(mappages(new, i, PGSIZE, (uint64)mem, flags) != 0){
      kfree(mem);
      goto err;
    }
  }
  return 0;

 err:
  uvmunmap(new, 0, i / PGSIZE, 1);
  return -1;
}

// mark a PTE invalid for user access.
// used by exec for the user stack guard page.

void
uvmclear(pagetable_t pagetable, uint64 va)
{
  pte_t *pte;

  pte = walk(pagetable, va, 0);
  if(pte == 0)
    panic("uvmclear");
  *pte &= ~PTE_U;
}

void uvmadd(pagetable_t pagetable, uint64 va, int perm) {
  pte_t *pte;

  pte = walk(pagetable, va, 0);
  if(pte == 0)
    panic("uvmset: pte should exist");
  if((*pte & PTE_V) == 0)
    panic("uvmset: page not present");
  if(PTE_FLAGS(*pte) == PTE_V)
    panic("uvmset: not a leaf");;
  *pte |= perm; // 设置权限
}
// 在pagetable中找dstva对应pa,将src开始len长字节copy到pa
// Copy from kernel to user.
// Copy len bytes from src to virtual address dstva in a given page table.
// Return 0 on success, -1 on error.

int
copyout(pagetable_t pagetable, uint64 dstva, char *src, uint64 len)
{
  uint64 n, va0, pa0;
  while(len > 0){
    va0 = PGROUNDDOWN(dstva);
    pa0 = walkaddr(pagetable, va0);
    if(pa0 == 0)
      return -1;
    n = PGSIZE - (dstva - va0);
    if(n > len)
      n = len;
    memmove((void *)(pa0 + (dstva - va0)), src, n);

    len -= n;
    src += n;
    dstva = va0 + PGSIZE;
  }
  return 0;
}

// dst -- pa
// srcva -- va
// Copy from user to kernel.
// Copy len bytes to dst from virtual address srcva in a given page table.
// Return 0 on success, -1 on error.

int
copyin(pagetable_t pagetable, char *dst, uint64 srcva, uint64 len)
{
  uint64 n, va0, pa0;

  while(len > 0){
    va0 = PGROUNDDOWN(srcva);
    pa0 = walkaddr(pagetable, va0);
    if(pa0 == 0)
      return -1;
    n = PGSIZE - (srcva - va0);
    if(n > len)
      n = len;
    memmove(dst, (void *)(pa0 + (srcva - va0)), n);

    len -= n;
    dst += n;
    srcva = va0 + PGSIZE;
  }
  return 0;
}

// Copy a null-terminated string from user to kernel.
// Copy bytes to dst from virtual address srcva in a given page table,
// until a '\0', or max.
// Return 0 on success, -1 on error.

int
copyinstr(pagetable_t pagetable, char *dst, uint64 srcva, uint64 max)
{
  uint64 n, va0, pa0;
  int got_null = 0;

  while(got_null == 0 && max > 0){
    va0 = PGROUNDDOWN(srcva);
    pa0 = walkaddr(pagetable, va0);
    if(pa0 == 0)
      return -1;
    n = PGSIZE - (srcva - va0);
    if(n > max)
      n = max;

    char *p = (char *) (pa0 + (srcva - va0));
    while(n > 0){
      if(*p == '\0'){
        *dst = '\0';
        got_null = 1;
        break;
      } else {
        *dst = *p;
      }
      --n;
      --max;
      p++;
      dst++;
    }

    srcva = va0 + PGSIZE;
  }
  if(got_null){
    return 0;
  } else {
    return -1;
  }
}



/// @brief allocate PGSIEZE memory for trapframe and map it to thread TRAMPFRAME space
/// @return trapframe pointer
/// @param pagetable user pagetable
/// @param thread_idx thread index
struct trapframe *uvm_thread_trapframe(pagetable_t pagetable, int thread_idx) {
    paddr_t pa = (paddr_t)kzalloc();

    if (mappages(pagetable, THREAD_TRAPFRAME(thread_idx), PGSIZE, pa, PTE_R | PTE_W) < 0) {
        kfree((void *)pa);
        return NULL;
    }

#ifdef __DEBUG_UVM_THREAD_TRAPFRAME
    Log("uvm_thread_trapframe: thread_idx %d, pa %p, va %p" ,thread_idx, pa, THREAD_TRAPFRAME(thread_idx));
    walk_va(pagetable, THREAD_TRAPFRAME(thread_idx));

#endif
    return (struct trapframe *)pa;
}

void
_vmprint(pte_t *pte, int level)
{
  if (level == 3) {
    return;
  }

  for (int i = 0; i < 512; i++) {
    if (pte[i]) {
      for (int j = 0; j <= level; j++)
        printf(" ..");
      printf("%d: pte %p pa %p\n", i, pte[i], PTE2PA(pte[i]));
      _vmprint((pte_t *)PTE2PA(pte[i]), level + 1);
    }
  }
}

